// Search pages to scan daily. Add/remove targets freely.
const targets = [
  { url: 'https://internshala.com/internships/product-management-internship/', role_hint: 'pm' },
  { url: 'https://internshala.com/internships/marketing-internship/', role_hint: 'growth' },
  { url: 'https://internshala.com/internships/data-analytics-internship/', role_hint: 'analyst' },
  { url: 'https://internshala.com/internships/software-development-internship/', role_hint: 'swe' },
  { url: 'https://internshala.com/internships/web-development-internship/', role_hint: 'swe' },
];
return targets.map(t => ({ json: { ...t, source: 'internshala' } }));

// Pull posting-detail links out of each search page.
// Internshala detail links look like /internship/detail/<slug>.
// If Internshala changes markup, only this regex needs updating.
const out = [];
const seen = new Set();
for (const item of $input.all()) {
  const html = item.json.data || '';
  const hint = $('Search URLs').all()[$input.all().indexOf(item)]?.json?.role_hint || 'other';
  const re = /href="(\/internship\/detail\/[^"]+)"/g;
  let m, count = 0;
  while ((m = re.exec(html)) !== null && count < 25) {
    const url = 'https://internshala.com' + m[1];
    if (seen.has(url)) continue;
    seen.add(url);
    out.push({ json: { source_url: url, role_hint: hint, source: 'internshala' } });
    count++;
  }
}
return out;

// Drop URLs we already have in the DB (no duplicate Claude spend).
const known = new Set(
  $('Fetch known URLs').all().map(i => i.json.source_url).filter(Boolean)
);
const seen = new Set();
return $('Parse posting links').all().filter(i => {
  const u = i.json.source_url;
  if (!u || known.has(u) || seen.has(u)) return false;
  seen.add(u);
  return true;
});

// Strip HTML to plain text and build the Anthropic API request body.
const SYSTEM = 'You extract structured data from internship job postings in India. Output ONLY a valid JSON object, no markdown fences, no commentary. If a field is not stated use null (arrays: [], booleans: false). Never guess stipend numbers. Schema: {"title":string,"company":string,"role_category":"pm"|"growth"|"analyst"|"swe"|"other","location":string|null,"city":string|null,"is_remote":boolean,"stipend_min_inr":integer|null,"stipend_max_inr":integer|null,"duration_months":number|null,"yoe_required":number,"ppo_offered":boolean,"posted_at":"YYYY-MM-DD"|null,"skills":[string],"perks":[string]}. Rules: stipend is monthly INR ("8-12k" -> min 8000 max 12000; "unpaid" -> 0; convert lakhs/year to monthly). city: one normalized Indian city (Bangalore, Mumbai, Delhi NCR, Hyderabad, Pune, Chennai, Kolkata, or the proper city name), null if remote-only. yoe_required: years of prior experience asked, 0 if none mentioned. posted_at: resolve relative dates against the given today date. skills: lowercase canonical tags (excel, sql, power bi, google analytics, figma, a/b testing, seo, communication...), exclude generic filler like "hardworking". role_category: pm=product roles, growth=marketing/growth/community, analyst=data/business/product analyst, swe=software/web/app/backend/frontend/qa/devops/ml engineering, else other.';
const srcs = $('Filter new postings').all();
const out = [];
$input.all().forEach((item, i) => {
  const html = item.json.data || '';
  if (!html) return;
  const meta = srcs[i] ? srcs[i].json : {};
  const text = html
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 6000);
  const today = new Date().toISOString().slice(0, 10);
  out.push({ json: {
    ...meta,
    raw_text: text,
    anthropic_body: {
      model: 'claude-haiku-4-5',
      max_tokens: 1024,
      temperature: 0,
      system: SYSTEM,
      messages: [{ role: 'user', content: `Today's date: ${today}\n\nPosting URL: ${meta.source_url}\nPosting text:\n---\n${text}\n---` }]
    }
  }});
});
return out;

// Parse Claude's JSON and shape a row matching the postings table exactly.
const reqs = $('Build Claude request').all();
const out = [];
$input.all().forEach((item, i) => {
  try {
    const txt = (item.json.content && item.json.content[0] && item.json.content[0].text) || '';
    const j = JSON.parse(txt.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim());
    const meta = reqs[i] ? reqs[i].json : {};
    out.push({ json: {
      source: meta.source || 'other',
      source_url: meta.source_url,
      raw_text: meta.raw_text,
      title: j.title,
      company: j.company,
      role_category: ['pm','growth','analyst','swe','other'].includes(j.role_category) ? j.role_category : (meta.role_hint || 'other'),
      location: j.location,
      city: j.city,
      is_remote: !!j.is_remote,
      stipend_min_inr: Number.isFinite(j.stipend_min_inr) ? Math.round(j.stipend_min_inr) : null,
      stipend_max_inr: Number.isFinite(j.stipend_max_inr) ? Math.round(j.stipend_max_inr) : null,
      duration_months: j.duration_months,
      yoe_required: Number.isFinite(j.yoe_required) ? j.yoe_required : 0,
      ppo_offered: typeof j.ppo_offered === 'boolean' ? j.ppo_offered : null,
      posted_at: /^\d{4}-\d{2}-\d{2}$/.test(j.posted_at || '') ? j.posted_at : null,
      skills: Array.isArray(j.skills) ? j.skills.map(s => String(s).toLowerCase().trim()) : [],
      perks: Array.isArray(j.perks) ? j.perks : [],
      extraction_model: 'claude-haiku-4-5',
      extraction_json: j
    }});
  } catch (e) { /* skip unparseable extractions; they stay unscraped and retry tomorrow */ }
});
return out;
